[AUDIT]
Regression test sends X-Gateway-User-Id with bogus signature and asserts Unauthorized. On current diff test fails — resolve_user returns User(id="admin") because bypass branch runs after verify()==False. After fix (fail-closed), test passes.

```python
import pytest
from app.middleware.auth import AuthMiddleware, Unauthorized

class FakeRequest:
    def __init__(self, headers=None, cookies=None):
        self.headers = headers or {}
        self.cookies = cookies or {}

@pytest.fixture
def mw():
    m = AuthMiddleware()
    m.sessions = {}
    m._verify = lambda uid, sig: sig == "valid-sig-for-" + uid
    return m

def test_forged_gateway_uid_rejected(mw):
    req = FakeRequest(headers={
        "X-Gateway-User-Id": "admin",
        "X-Gateway-Signature": "deadbeef",
    })
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_missing_signature_rejected(mw):
    req = FakeRequest(headers={"X-Gateway-User-Id": "admin"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_legacy_x_user_id_rejected(mw):
    req = FakeRequest(headers={"X-User-Id": "admin"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)

def test_valid_gateway_uid_accepted(mw):
    req = FakeRequest(headers={
        "X-Gateway-User-Id": "alice",
        "X-Gateway-Signature": "valid-sig-for-alice",
    })
    user = mw.resolve_user(req)
    assert user.id == "alice"
```

